const ROMAN_GODS_BY_SLUG: Record<string, RomanGodGuide> = Object.fromEntries(ROMAN_GODS.map((g) => [g.slug, g]))

export const ROMAN_GODS_SLUGS = ROMAN_GODS.map((g) => g.slug)

export function isRomanGodSlug(s: string): boolean {
  return s in ROMAN_GODS_BY_SLUG
}

